def get_rate(table, boat, diff):
    if boat not in table: return {'1着率':0,'2着率':0,'3着率':0,'3連対率':0}
    for (mn,mx), r in table[boat].items():
        if mn <= diff < mx: return r
    return {'1着率':0,'2着率':0,'3着率':0,'3連対率':0}

def calc(df, pat, tbl):
    res = []
    for _, b in df.iterrows():
        ex, ol = float(b['exhibition']), float(b['one_lap'])
        th = float(b['turning'] if pat=='A' else b['straight'])
        lbl = '周り足' if pat=='A' else '直線'
        res.append({'number':int(b['number']),'exhibition':ex,'one_lap':ol,'third':th,'third_label':lbl,'shinsum':ex+ol+th})
    avg = sum(r['shinsum'] for r in res)/len(res)
    for r in res:
        r['diff_raw'], r['diff'], r['avg'] = r['shinsum']-avg, avg-r['shinsum'], avg
        rt = get_rate(tbl, r['number'], r['diff_raw'])
        r.update({'rate_1':rt['1着率'],'rate_2':rt['2着率'],'rate_3':rt['3着率'],'rate_renntai':rt['3連対率']})
    return res

def gen_html(csv, dt, tbls):
    if not os.path.exists(csv): return print(f'❌ {csv} not found')
    df = pd.read_csv(csv)
    df = df[df['venue_name'].isin(VENUE_PATTERNS.keys())]
    if len(df)==0: return print('⚠️  No data')
    
    h = f'''<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>シンsum理論</title>
<style>*{{margin:0;padding:0;box-sizing:border-box}}body{{font-family:'Hiragino Sans',sans-serif;background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);min-height:100vh;padding:20px}}.container{{max-width:1400px;margin:0 auto}}header{{background:white;padding:30px;border-radius:15px;box-shadow:0 10px 30px rgba(0,0,0,0.2);margin-bottom:30px;text-align:center}}h1{{color:#333;font-size:2.5em;margin-bottom:10px}}.venue-tabs{{display:flex;flex-wrap:wrap;gap:10px;background:white;padding:20px;border-radius:15px;box-shadow:0 10px 30px rgba(0,0,0,0.2);margin-bottom:30px}}.tab-button{{padding:12px 24px;border:none;background:#f0f0f0;border-radius:8px;cursor:pointer;font-size:1em;font-weight:bold;transition:all 0.3s}}.tab-button:hover{{background:#667eea;color:white;transform:translateY(-2px)}}.tab-button.active{{background:#667eea;color:white}}.venue-content{{display:none}}.venue-content.active{{display:block}}.race-card{{background:white;padding:25px;border-radius:15px;box-shadow:0 10px 30px rgba(0,0,0,0.2);margin-bottom:20px}}.race-title{{font-size:1.5em;color:#667eea;margin-bottom:15px;padding-bottom:10px;border-bottom:3px solid #667eea}}table{{width:100%;border-collapse:collapse;margin-top:10px}}th,td{{padding:12px 8px;text-align:center;border-bottom:1px solid #eee;font-size:0.95em}}th{{background:#f8f9fa;font-weight:bold;color:#333}}tr:hover{{background:#f8f9fa}}.boat-1,.boat-2{{border-left:4px solid #000}}.boat-3{{border-left:4px solid #ff0000}}.boat-4{{border-left:4px solid #0000ff}}.boat-5{{border-left:4px solid #ffff00}}.boat-6{{border-left:4px solid #00ff00}}.positive{{color:#28a745;font-weight:bold}}.negative{{color:#dc3545;font-weight:bold}}.rate-box{{display:inline-block;padding:4px 8px;border-radius:4px;font-weight:bold}}.rate-positive{{background:#d4edda;color:#155724}}.rate-negative{{background:#f8d7da;color:#721c24}}.rate-neutral{{background:#e2e3e5;color:#383d41}}</style></head><body><div class="container"><header><h1>🚤 シンsum理論</h1><p class="date">{dt}</p></header><div class="venue-tabs">'''
    
    vns = df['venue_name'].unique()
    for i,v in enumerate(vns):
        h += f'<button class="tab-button{"active"if i==0 else""}" onclick="showVenue(\'{v}\')">{v}</button>'
    h += '</div>'
    
    for i,v in enumerate(vns):
        h += f'<div class="venue-content{"active"if i==0 else""}" id="{v}">'
        for rn, rd in df[df['venue_name']==v].groupby('race_no'):
            sr = calc(rd, VENUE_PATTERNS[v], tbls[v])
            if not sr: continue
            lbl = sr[0]['third_label']
            h += f'<div class="race-card"><h2 class="race-title">{rn}R（平均: {sr[0]["avg"]:.2f}）</h2><table><thead><tr><th>艇番</th><th>展示</th><th>1周</th><th>{lbl}</th><th>シンsum</th><th>平均との差</th><th>1着率</th><th>2着率</th><th>3着率</th><th>3連対率</th></tr></thead><tbody>'
            for r in sr:
                dc = 'positive'if r['diff']>0 else'negative'if r['diff']<0 else''
                ds = '+'if r['diff']>0 else''
                rc = lambda x: 'rate-positive'if x>0 else'rate-negative'if x<0 else'rate-neutral'
                rs = lambda x: f'+{x}'if x>0 else str(x)
                h += f'<tr class="boat-{r["number"]}"><td><strong>{r["number"]}号艇</strong></td><td>{r["exhibition"]:.2f}</td><td>{r["one_lap"]:.2f}</td><td>{r["third"]:.2f}</td><td><strong>{r["shinsum"]:.2f}</strong></td><td class="{dc}"><strong>{ds}{r["diff"]:.2f}</strong></td><td><span class="rate-box {rc(r["rate_1"])}">{rs(r["rate_1"])}%</span></td><td><span class="rate-box {rc(r["rate_2"])}">{rs(r["rate_2"])}%</span></td><td><span class="rate-box {rc(r["rate_3"])}">{rs(r["rate_3"])}%</span></td><td><span class="rate-box {rc(r["rate_renntai"])}">{rs(r["rate_renntai"])}%</span></td></tr>'
            h += '</tbody></table></div>'
        h += '</div>'
    
    h += '''</div><script>function showVenue(v){document.querySelectorAll('.tab-button').forEach(b=>b.classList.remove('active'));document.querySelectorAll('.venue-content').forEach(c=>c.classList.remove('active'));event.currentTarget.classList.add('active');document.getElementById(v).classList.add('active');window.scrollTo({top:0,behavior:'smooth'});localStorage.setItem('selectedVenue',v);}window.addEventListener('DOMContentLoaded',function(){var s=localStorage.getItem('selectedVenue');if(s&&document.getElementById(s)){document.querySelectorAll('.tab-button').forEach(function(b){b.classList.remove('active');if(b.textContent===s)b.classList.add('active')});document.querySelectorAll('.venue-content').forEach(function(c){c.classList.remove('active')});document.getElementById(s).classList.add('active')}});</script></body></html>'''
    return h

csv_files = glob.glob('all_races_*.csv')
if not csv_files: exit(print('❌ CSVファイルが見つかりません'))
csv = sorted(csv_files)[-1]
dm = re.search(r'(\d{8})', csv)
dt = f'{dm.group(1)[0:4]}年{dm.group(1)[4:6]}月{dm.group(1)[6:8]}日' if dm else datetime.now().strftime('%Y年%m月%d日')
print(f'🚤 シンsum理論 完全版\n{"="*60}\n📄 {csv}\n📖 基準表読み込み済み（6会場）\n')
html = gen_html(csv, dt, RATE_TABLES)
if html:
    with open('shinsum_complete.html','w',encoding='utf-8') as f: f.write(html)
    print(f'{"="*60}\n🎉 完了！\n{"="*60}\n✅ shinsum_complete.html\n💡 open shinsum_complete.html')